import{_ as o,o as r,c as t,a5 as l}from"./chunks/framework.B5tqjWbr.js";const h=JSON.parse('{"title":"教程 0019：单相逆变器比例谐振控制（proportional resonant control / PR control）","description":"","frontmatter":{"title":"教程 0019：单相逆变器比例谐振控制（proportional resonant control / PR control）","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0019-single-phase-inverter-pr-control.html","status":"learning","visibility":"public","summary":"Imported from 0019-single-phase-inverter-pr-control.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0019-single-phase-inverter-pr-control.md","filePath":"content/power/lessons/0019-single-phase-inverter-pr-control.md","lastUpdated":null}'),p={name:"content/power/lessons/0019-single-phase-inverter-pr-control.md"};function a(i,e,n,c,d,s){return r(),t("div",null,[...e[0]||(e[0]=[l(`<h1 id="教程-0019-单相逆变器比例谐振控制-proportional-resonant-control-pr-control" tabindex="-1">教程 0019：单相逆变器比例谐振控制（proportional resonant control / PR control） <a class="header-anchor" href="#教程-0019-单相逆变器比例谐振控制-proportional-resonant-control-pr-control" aria-label="Permalink to &quot;教程 0019：单相逆变器比例谐振控制（proportional resonant control / PR control）&quot;">​</a></h1><p>中文主讲，一个概念，一个仿真任务：对 50 Hz 正弦输出，PR 控制在基波频率处提高误差校正能力，比普通比例控制更适合单相逆变器电压环。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>一个仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用教学模型和教学参数，不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>比例谐振控制（proportional resonant control / PR control）是一种针对交流正弦量的控制方法。比例项看当前误差，谐振项专门记住目标频率附近的误差。</p><p>本节场景是单相全桥逆变器（single-phase full-bridge inverter）经过 LC 滤波器（inductor-capacitor filter / LC filter）后输出 50 Hz 正弦电压。PR 控制放在电压环（voltage loop）里，输出调制命令，再交给脉宽调制（pulse-width modulation / PWM）执行。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）逆变器要在负载变化时仍保持输出电压接近正弦参考。负载越重，滤波电感和功率级上的压降越明显；如果只靠普通比例控制，50 Hz 正弦误差通常会留下残余。</p><p>PR 控制的价值是：它不是笼统地把所有频率的误差都放大，而是在目标基波频率处给很强的纠偏能力。这对单相交流输出很自然，也方便你以后读逆变器电压环 C 代码时识别 <code>Kp</code>、<code>Kr</code>、谐振状态、限幅和保护之间的关系。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>比例控制像“看到误差就推一下”。对直流量，这个方法很直接；但对持续旋转的正弦量，误差方向每一刻都在变化，单纯比例项往往只能减小误差，不能很好地消除误差。</p><p>PR 控制像一个只盯住 50 Hz 的记忆器。如果输出电压长期比参考低一点，谐振项会把这个 50 Hz 误差积累起来，并在正确相位给出补偿。它不是魔法，只是在指定频率处提高环路增益。</p><pre><code>正弦参考
v_ref

误差计算
e = vref - vout

PR 电压环
Kp, Kr, 50Hz

PWM/功率级
m_cmd

输出电压反馈到误差计算
本节只看50Hz基波误差校正，暂不讲谐波补偿和并联系统
</code></pre><p>图 1：PR 控制处在正弦参考、输出反馈和 PWM 执行之间。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>连续域常见 PR 控制器可以写成：</p><p>Gpr(s) = Kp + Kr * 2<em>wc</em>s / (s^2 + 2<em>wc</em>s + w0^2)</p><p>为了让物理意义更直观，本节仿真使用同步投影形式记住 50 Hz 误差：</p><p>e = v_ref - v_out xs += e * sin(theta) * dt xc += e * cos(theta) * dt u_res = Kr * (xs<em>sin(theta) + xc</em>cos(theta)) m_cmd = clamp(v_ref/Vdc + Kp*e + u_res/Vdc, -m_limit, m_limit)</p><p><code>xs</code> 和 <code>xc</code> 可以理解成“50 Hz 误差记忆”。真实产品常用不同离散化形式，本节公式只服务于理解，不代表公司内部实现。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\single_phase_inverter_pr_control.py</p><p>脚本会生成并自动打开图；如果无法自动打开，会打印完整路径。图中包含 Vdc、Vout_ref、f_out、L、C、负载阶跃、Kp、Kr、控制频率、调制限幅、仿真时长和跟踪误差。</p><pre><code>一个仿真任务
python simulations\\python\\single_phase_inverter_pr_control.py --resonant-gain 0 --output simulations\\results\\inverter_pr_Kr_0.png
</code></pre><p>python simulations\\python\\single_phase_inverter_pr_control.py --resonant-gain 80 --output simulations\\results\\inverter_pr_Kr_80.png</p><p>对比 <code>Kr=0</code> 和 <code>Kr=80</code> 时，负载阶跃后的 <code>Voltage error e_v</code>、<code>m_cmd</code> 和尾段跟踪误差。文件名和图内参数框都标出当前参数条件。</p><p>观察顺序：</p><ul><li><p>先看 <code>v_ref</code> 和 <code>v_out</code> 是否贴近。</p></li><li><p>再看负载阶跃后 <code>Voltage error e_v</code> 是否恢复。</p></li><li><p>检查 <code>m_cmd</code> 是否碰到 <code>m_limit</code>，避免把过调制误认为控制效果。</p></li><li><p>最后看 <code>i_load</code>，确认负载变重后输出电流确实增大。</p></li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>读固件时可以按下面链路找变量：</p><p>ADC Vout, iL, Vdc -&gt; voltage reference from sine table or PLL angle -&gt; e_v = v_ref - v_out -&gt; PR voltage controller -&gt; modulation command limit -&gt; PWM compare update -&gt; protection checks</p><p>工程上必须关注离散化、限幅、抗饱和、采样延迟、频率偏移和保护优先级。比如 <code>m_cmd</code> 长期贴着限幅，说明控制器已经没有调制裕量，此时继续加大 <code>Kr</code> 可能只会让波形和保护更难处理。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**PR 控制就是 PI 控制换个名字。 **纠正：**比例积分（proportional integral / PI）更适合直流量零误差；PR 更适合交流正弦量在指定频率处小误差。</p></li><li><p><strong>误解：</strong><code>Kr</code> 越大越好。 **纠正：**过大的谐振增益可能放大噪声、引起振荡、触发调制限幅，甚至激发 LC 谐振问题。</p></li><li><p>**误解：**PR 跟踪误差小，就不需要保护逻辑。 **纠正：**短路、过流、母线异常、采样故障和过调制仍然必须由保护和状态机处理。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能解释 <code>Kp</code>、<code>Kr</code>、<code>e_v</code>、<code>m_cmd</code> 各自代表什么。</p></li><li><p>能说出 PR 为什么比单纯比例控制更适合 50 Hz 正弦电压跟踪。</p></li><li><p>能根据图内参数框读出 Vdc、Vout_ref、f_out、L、C、负载阶跃、Kp、Kr、f_ctrl 和 t_end。</p></li><li><p>能解释为什么检查调制限幅是判断控制效果的必要步骤。</p></li><li><p>能基于仿真图准备导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p>为什么 <code>Kr=0</code> 时仍可能有明显的 50 Hz 跟踪误差？</p></li><li><p>如果把 <code>Kr</code> 继续加大，除了误差变小，还可能带来哪些风险？</p></li><li><p>负载从 <code>48.4 ohm</code> 变到 <code>32 ohm</code> 后，为什么要同时观察 <code>v_out</code>、<code>e_v</code>、<code>m_cmd</code> 和 <code>i_load</code>？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>single_phase_inverter_pr_control.py</code> 看到 <code>Kr=80</code> 比 <code>Kr=0</code> 的 50 Hz 跟踪误差小很多。公司 UPS 逆变器电压环通常用 PR、PI 旋转坐标系，还是其他结构？</p></li><li><p>仿真里 <code>m_cmd</code> 没有触碰 <code>m_limit=0.95</code>。真实固件里 PR 输出限幅后，是否有抗饱和处理或故障计数？</p></li><li><p>负载从 <code>48.4 ohm</code> 变到 <code>32 ohm</code> 后，<code>i_load</code> 增大但 <code>v_out</code> 恢复到参考附近。真实调试时会怎样区分控制环带宽不足、LC 参数问题和限流保护介入？</p></li></ul><p>**下一步：**可以继续把 PR 电压环放进更接近固件的离散实现，观察采样延迟、限幅和抗饱和对逆变器输出的影响。</p><p>关联：<a href="./0018-single-phase-inverter-lc-filter.html">上一节：单相逆变器 LC 输出滤波</a>；源稿：<code>concepts/control/single-phase-inverter-pr-control.md</code>。</p><pre><code>上一节：教程 0018：单相全桥逆变器（single-phase full-bridge inverter）的 LC 输出滤波
下一节：教程 0020：单相逆变器的均方根（root mean square / RMS）估算与欠压保护
</code></pre>`,46)])])}const u=o(p,[["render",a]]);export{h as __pageData,u as default};
